import{_ as n,o as a,c as o,a2 as e}from"./chunks/framework.B72_uj9U.js";const d=JSON.parse('{"title":"Message Formats","description":"The structure of conversation messages across LLM APIs, including roles, content blocks, and multi-modal inputs.","frontmatter":{"title":"Message Formats","description":"The structure of conversation messages across LLM APIs, including roles, content blocks, and multi-modal inputs."},"headers":[],"relativePath":"learn/linear/03-understanding-llms/06-message-formats.md","filePath":"learn/linear/03-understanding-llms/06-message-formats.md"}'),t={name:"learn/linear/03-understanding-llms/06-message-formats.md"};function l(p,s,r,c,i,y){return a(),o("div",null,[...s[0]||(s[0]=[e(`<h1 id="message-formats" tabindex="-1">Message Formats <a class="header-anchor" href="#message-formats" aria-label="Permalink to &quot;Message Formats&quot;">​</a></h1><blockquote><p><strong>What you&#39;ll learn:</strong></p><ul><li>How messages are structured with roles (system, user, assistant) and content blocks</li><li>The differences between Anthropic and OpenAI message format conventions</li><li>How tool use messages, tool results, and multi-turn conversations are represented in the message array</li></ul></blockquote><p>Every API call to an LLM includes a messages array -- the conversation history that the model uses to generate its response. Understanding the exact structure of this array is essential because your agent constructs it on every iteration of the agentic loop. Get the format wrong and the API rejects your request. Get the structure suboptimal and the model makes poor decisions because it misunderstands the conversation state.</p><h2 id="the-messages-array" tabindex="-1">The Messages Array <a class="header-anchor" href="#the-messages-array" aria-label="Permalink to &quot;The Messages Array&quot;">​</a></h2><p>Both Anthropic and OpenAI structure conversations as an ordered array of message objects. Each message has a <strong>role</strong> and <strong>content</strong>. The messages must alternate between <code>user</code> and <code>assistant</code> roles (with some exceptions for tool results).</p><p>Here is the simplest possible conversation:</p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">messages</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> [</span></span>
<span class="line"><span style="color:#9399B2;">    {</span><span style="color:#9399B2;">&quot;</span><span style="color:#89B4FA;">role</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;user&quot;</span><span style="color:#9399B2;">,</span><span style="color:#9399B2;"> &quot;</span><span style="color:#89B4FA;">content</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;What is the Rust equivalent of Python&#39;s dict?&quot;</span><span style="color:#9399B2;">}</span></span>
<span class="line"><span style="color:#9399B2;">  ]</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>And a multi-turn conversation:</p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">messages</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> [</span></span>
<span class="line"><span style="color:#9399B2;">    {</span><span style="color:#9399B2;">&quot;</span><span style="color:#89B4FA;">role</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;user&quot;</span><span style="color:#9399B2;">,</span><span style="color:#9399B2;"> &quot;</span><span style="color:#89B4FA;">content</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;What is the Rust equivalent of Python&#39;s dict?&quot;</span><span style="color:#9399B2;">},</span></span>
<span class="line"><span style="color:#9399B2;">    {</span><span style="color:#9399B2;">&quot;</span><span style="color:#89B4FA;">role</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;assistant&quot;</span><span style="color:#9399B2;">,</span><span style="color:#9399B2;"> &quot;</span><span style="color:#89B4FA;">content</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;The Rust equivalent is \`HashMap\` from the \`std::collections\` module.&quot;</span><span style="color:#9399B2;">},</span></span>
<span class="line"><span style="color:#9399B2;">    {</span><span style="color:#9399B2;">&quot;</span><span style="color:#89B4FA;">role</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;user&quot;</span><span style="color:#9399B2;">,</span><span style="color:#9399B2;"> &quot;</span><span style="color:#89B4FA;">content</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;How do I iterate over it?&quot;</span><span style="color:#9399B2;">}</span></span>
<span class="line"><span style="color:#9399B2;">  ]</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>The model receives the entire array and generates the next assistant response. It does not have memory between API calls -- your agent is responsible for accumulating messages and sending the full history every time.</p><h2 id="roles" tabindex="-1">Roles <a class="header-anchor" href="#roles" aria-label="Permalink to &quot;Roles&quot;">​</a></h2><h3 id="user" tabindex="-1">User <a class="header-anchor" href="#user" aria-label="Permalink to &quot;User&quot;">​</a></h3><p>The <code>user</code> role represents messages from the human (or, in an agent context, messages composed by the agent on behalf of the user). User messages are the primary input that drives the model&#39;s response.</p><h3 id="assistant" tabindex="-1">Assistant <a class="header-anchor" href="#assistant" aria-label="Permalink to &quot;Assistant&quot;">​</a></h3><p>The <code>assistant</code> role represents messages previously generated by the model. By including assistant messages in the history, you give the model context about what it has already said and done. This is critical for multi-turn agents -- without the assistant&#39;s previous responses, the model has no idea what tools it already called or what code it already wrote.</p><h3 id="system-openai-system-field-anthropic" tabindex="-1">System (OpenAI) / System Field (Anthropic) <a class="header-anchor" href="#system-openai-system-field-anthropic" aria-label="Permalink to &quot;System (OpenAI) / System Field (Anthropic)&quot;">​</a></h3><p>The system role works differently between providers:</p><p><strong>Anthropic</strong> places the system prompt in a top-level <code>system</code> field, separate from the messages array:</p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">model</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;claude-sonnet-4-20250514&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">system</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;You are an expert Rust coding assistant.&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">messages</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> [</span></span>
<span class="line"><span style="color:#9399B2;">    {</span><span style="color:#9399B2;">&quot;</span><span style="color:#89B4FA;">role</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;user&quot;</span><span style="color:#9399B2;">,</span><span style="color:#9399B2;"> &quot;</span><span style="color:#89B4FA;">content</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;Help me fix this error&quot;</span><span style="color:#9399B2;">}</span></span>
<span class="line"><span style="color:#9399B2;">  ]</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p><strong>OpenAI</strong> places the system prompt as the first message with <code>role: &quot;system&quot;</code>:</p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">model</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;gpt-4o&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">messages</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> [</span></span>
<span class="line"><span style="color:#9399B2;">    {</span><span style="color:#9399B2;">&quot;</span><span style="color:#89B4FA;">role</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;system&quot;</span><span style="color:#9399B2;">,</span><span style="color:#9399B2;"> &quot;</span><span style="color:#89B4FA;">content</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;You are an expert Rust coding assistant.&quot;</span><span style="color:#9399B2;">},</span></span>
<span class="line"><span style="color:#9399B2;">    {</span><span style="color:#9399B2;">&quot;</span><span style="color:#89B4FA;">role</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;user&quot;</span><span style="color:#9399B2;">,</span><span style="color:#9399B2;"> &quot;</span><span style="color:#89B4FA;">content</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;Help me fix this error&quot;</span><span style="color:#9399B2;">}</span></span>
<span class="line"><span style="color:#9399B2;">  ]</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>When building a provider-agnostic agent, you will store the system prompt separately in your internal data model and inject it in the correct location based on which provider you are calling.</p><h2 id="content-blocks-anthropic" tabindex="-1">Content Blocks (Anthropic) <a class="header-anchor" href="#content-blocks-anthropic" aria-label="Permalink to &quot;Content Blocks (Anthropic)&quot;">​</a></h2><p>Anthropic&#39;s API supports a richer content format where the <code>content</code> field can be either a plain string or an array of content blocks. This is how Anthropic represents multi-part messages, including tool use:</p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">role</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;assistant&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">content</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> [</span></span>
<span class="line"><span style="color:#9399B2;">    {</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">type</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;text&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">text</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;I&#39;ll read the file first to understand the current implementation.&quot;</span></span>
<span class="line"><span style="color:#9399B2;">    },</span></span>
<span class="line"><span style="color:#9399B2;">    {</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">type</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;tool_use&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">id</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;toolu_01A09q90qw90lq917835lq9&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">name</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;read_file&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">input</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span><span style="color:#9399B2;">&quot;</span><span style="color:#89B4FA;">path</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;src/main.rs&quot;</span><span style="color:#9399B2;">}</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"><span style="color:#9399B2;">  ]</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>This is a single assistant message that contains both text and a tool call. The content block format lets the model express &quot;here is my reasoning, and here is the action I am taking&quot; in one message.</p><p>The content block types you will encounter in Anthropic&#39;s API:</p><table tabindex="0"><thead><tr><th>Type</th><th>Used In</th><th>Purpose</th></tr></thead><tbody><tr><td><code>text</code></td><td>user, assistant</td><td>Plain text content</td></tr><tr><td><code>tool_use</code></td><td>assistant</td><td>Model requests a tool call</td></tr><tr><td><code>tool_result</code></td><td>user</td><td>Agent returns tool execution result</td></tr><tr><td><code>image</code></td><td>user</td><td>Image input (base64 or URL)</td></tr></tbody></table><h2 id="tool-use-message-flow" tabindex="-1">Tool Use Message Flow <a class="header-anchor" href="#tool-use-message-flow" aria-label="Permalink to &quot;Tool Use Message Flow&quot;">​</a></h2><p>The most important message pattern for agents is the tool use cycle. Here is the complete flow using Anthropic&#39;s format:</p><p><strong>Turn 1: User sends a request</strong></p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#9399B2;">{</span><span style="color:#9399B2;">&quot;</span><span style="color:#89B4FA;">role</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;user&quot;</span><span style="color:#9399B2;">,</span><span style="color:#9399B2;"> &quot;</span><span style="color:#89B4FA;">content</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;What files are in the src directory?&quot;</span><span style="color:#9399B2;">}</span></span></code></pre></div><p><strong>Turn 2: Assistant responds with a tool call</strong></p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">role</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;assistant&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">content</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> [</span></span>
<span class="line"><span style="color:#9399B2;">    {</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">type</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;text&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">text</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;Let me check the contents of the src directory.&quot;</span></span>
<span class="line"><span style="color:#9399B2;">    },</span></span>
<span class="line"><span style="color:#9399B2;">    {</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">type</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;tool_use&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">id</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;toolu_01XFDUDYJgAACzvnptvVer6C&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">name</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;shell&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">input</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span><span style="color:#9399B2;">&quot;</span><span style="color:#89B4FA;">command</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;ls src/&quot;</span><span style="color:#9399B2;">}</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"><span style="color:#9399B2;">  ]</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p><strong>Turn 3: User role message containing the tool result</strong></p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">role</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;user&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">content</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> [</span></span>
<span class="line"><span style="color:#9399B2;">    {</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">type</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;tool_result&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">tool_use_id</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;toolu_01XFDUDYJgAACzvnptvVer6C&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">content</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;main.rs</span><span style="color:#F5C2E7;">\\n</span><span style="color:#A6E3A1;">lib.rs</span><span style="color:#F5C2E7;">\\n</span><span style="color:#A6E3A1;">tools/</span><span style="color:#F5C2E7;">\\n</span><span style="color:#A6E3A1;">config.rs&quot;</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"><span style="color:#9399B2;">  ]</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p><strong>Turn 4: Assistant processes the result and responds</strong></p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">role</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;assistant&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">content</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> [</span></span>
<span class="line"><span style="color:#9399B2;">    {</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">type</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;text&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">text</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;The src directory contains:</span><span style="color:#F5C2E7;">\\n</span><span style="color:#A6E3A1;">- \`main.rs\` - the entry point</span><span style="color:#F5C2E7;">\\n</span><span style="color:#A6E3A1;">- \`lib.rs\` - the library root</span><span style="color:#F5C2E7;">\\n</span><span style="color:#A6E3A1;">- \`tools/\` - a directory for tool implementations</span><span style="color:#F5C2E7;">\\n</span><span style="color:#A6E3A1;">- \`config.rs\` - configuration handling&quot;</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"><span style="color:#9399B2;">  ]</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>Notice that the tool result is sent as a <code>user</code> role message. This maintains the alternating user/assistant pattern. The <code>tool_use_id</code> links the result back to the specific tool call, which is important when the model makes multiple tool calls in one turn.</p><div class="custom-block python"><p class="custom-block-title">Coming from Python</p><p>In Python, you might represent conversation history as a list of dictionaries: <code>messages = [{&quot;role&quot;: &quot;user&quot;, &quot;content&quot;: &quot;...&quot;}]</code>. In Rust, you will define an enum for roles and a struct for messages. The Anthropic content block format maps well to Rust enums -- a <code>ContentBlock</code> enum with variants for <code>Text</code>, <code>ToolUse</code>, and <code>ToolResult</code> is a natural representation.</p></div><h2 id="openai-s-tool-message-format" tabindex="-1">OpenAI&#39;s Tool Message Format <a class="header-anchor" href="#openai-s-tool-message-format" aria-label="Permalink to &quot;OpenAI&#39;s Tool Message Format&quot;">​</a></h2><p>OpenAI handles tool use messages differently. Instead of content blocks, tool calls appear as a separate field on the assistant message, and tool results use a dedicated <code>tool</code> role:</p><p><strong>Assistant message with tool call:</strong></p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">role</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;assistant&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">content</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#FAB387;"> null</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">tool_calls</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> [</span></span>
<span class="line"><span style="color:#9399B2;">    {</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">id</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;call_abc123&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">type</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;function&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">function</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#9399B2;">        &quot;</span><span style="color:#89B4FA;">name</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;shell&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">        &quot;</span><span style="color:#89B4FA;">arguments</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;{</span><span style="color:#F5C2E7;">\\&quot;</span><span style="color:#A6E3A1;">command</span><span style="color:#F5C2E7;">\\&quot;</span><span style="color:#A6E3A1;">: </span><span style="color:#F5C2E7;">\\&quot;</span><span style="color:#A6E3A1;">ls src/</span><span style="color:#F5C2E7;">\\&quot;</span><span style="color:#A6E3A1;">}&quot;</span></span>
<span class="line"><span style="color:#9399B2;">      }</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"><span style="color:#9399B2;">  ]</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p><strong>Tool result message:</strong></p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">role</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;tool&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">tool_call_id</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;call_abc123&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">content</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;main.rs</span><span style="color:#F5C2E7;">\\n</span><span style="color:#A6E3A1;">lib.rs</span><span style="color:#F5C2E7;">\\n</span><span style="color:#A6E3A1;">tools/</span><span style="color:#F5C2E7;">\\n</span><span style="color:#A6E3A1;">config.rs&quot;</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>Key differences from Anthropic:</p><ul><li>Tool calls are in a <code>tool_calls</code> array on the assistant message, not in content blocks</li><li>The <code>arguments</code> field is a JSON string, not a parsed object</li><li>Tool results use <code>role: &quot;tool&quot;</code> instead of being wrapped in a user message</li><li>The linking field is <code>tool_call_id</code> instead of <code>tool_use_id</code></li></ul><h2 id="message-ordering-rules" tabindex="-1">Message Ordering Rules <a class="header-anchor" href="#message-ordering-rules" aria-label="Permalink to &quot;Message Ordering Rules&quot;">​</a></h2><p>Both APIs enforce strict ordering rules:</p><ol><li><strong>Messages must alternate between user and assistant</strong> (with tool results being considered part of the user turn in Anthropic, or allowed between assistant and user turns in OpenAI)</li><li><strong>The first message must be from the user</strong> (after the system message, if using OpenAI format)</li><li><strong>Every tool call must have a corresponding tool result</strong> -- if the assistant requests a tool call, the next message must contain the result for that call</li><li><strong>Tool results must reference valid tool call IDs</strong> -- the <code>tool_use_id</code> or <code>tool_call_id</code> must match an ID from a preceding assistant message</li></ol><p>Violating these rules produces API errors that can be confusing if you do not understand the expected structure. Your agent&#39;s message management code needs to enforce these invariants.</p><h2 id="building-the-provider-abstraction" tabindex="-1">Building the Provider Abstraction <a class="header-anchor" href="#building-the-provider-abstraction" aria-label="Permalink to &quot;Building the Provider Abstraction&quot;">​</a></h2><p>Since Anthropic and OpenAI use different message formats, a well-designed agent defines an internal message format and converts to the provider-specific format at the API boundary:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;">// Your internal representation</span></span>
<span class="line"><span style="color:#CBA6F7;">enum</span><span style="color:#F9E2AF;font-style:italic;"> Role</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">    User</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">    Assistant</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">    System</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">enum</span><span style="color:#F9E2AF;font-style:italic;"> ContentBlock</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    Text</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;font-style:italic;">String</span><span style="color:#9399B2;">),</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">    ToolUse</span><span style="color:#9399B2;"> {</span><span style="color:#CDD6F4;"> id</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> String</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> name</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> String</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> input</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;"> serde_json</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">Value</span><span style="color:#9399B2;"> },</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">    ToolResult</span><span style="color:#9399B2;"> {</span><span style="color:#CDD6F4;"> tool_use_id</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> String</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> content</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> String</span><span style="color:#9399B2;"> },</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">struct</span><span style="color:#F9E2AF;font-style:italic;"> Message</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CDD6F4;">    role</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> Role</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">    content</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> Vec</span><span style="color:#89DCEB;">&lt;</span><span style="color:#F9E2AF;font-style:italic;">ContentBlock</span><span style="color:#89DCEB;">&gt;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>Then you write serialization functions that convert <code>Message</code> to the Anthropic or OpenAI JSON format. This abstraction is critical for a provider-agnostic agent and is something we will build in detail in later chapters.</p><div class="custom-block wild"><p class="custom-block-title">In the Wild</p><p>OpenCode, an open-source coding agent, defines a unified message format internally and implements provider-specific serializers for Anthropic and OpenAI. This allows the core agent loop to work identically regardless of which provider is configured. Claude Code, being an Anthropic product, works directly with the Anthropic message format but still maintains clean internal abstractions for message construction.</p></div><h2 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h2><ul><li>The messages array is an ordered sequence of role-tagged messages that your agent constructs and sends on every API call -- the model has no memory between calls</li><li>Anthropic uses content blocks (arrays of typed objects) within messages to represent mixed content like text alongside tool calls, while OpenAI uses separate fields and a dedicated <code>tool</code> role</li><li>The tool use message cycle follows a strict pattern: user request, assistant tool call, tool result (linked by ID), assistant follow-up -- violating this pattern produces API errors</li><li>Building a provider-agnostic agent requires an internal message representation that is converted to provider-specific JSON at the API boundary</li><li>Every tool call must have a corresponding tool result with a matching ID, and messages must maintain the alternating role pattern each API expects</li></ul>`,59)])])}const B=n(t,[["render",l]]);export{d as __pageData,B as default};
